mapper.select:
SELECT w.waybill_id, w.qty, COALESCE(w.start_no, '') AS start_no, COALESCE(w.end_no, '') AS end_no, w.sender_company_id, /* waybillžóź ÍįížĚī žěąžúľŽ©ī žöįžĄ† žā¨žö©, žóÜžúľŽ©ī company ŪÖĆžĚīŽłĒ Íįí žā¨žö© */ COALESCE(w.sender_company_nm, sender.company_nm) AS sender_company_nm, w.sender_tel_no, w.sender_manager_tel_no, w.sender_address, w.receiver_company_id, /* waybillžóź ÍįížĚī žěąžúľŽ©ī žöįžĄ† žā¨žö©, žóÜžúľŽ©ī company ŪÖĆžĚīŽłĒ Íįí žā¨žö© */ COALESCE(w.receiver_company_nm, receiver.company_nm) AS receiver_company_nm, w.receiver_tel_no, w.receiver_manager_tel_no, w.receiver_address, w.reg_id, w.reg_dt, w.chg_id, w.chg_dt, w.del_yn FROM waybill w /* ÍĶ¨ ŽćįžĚīŪĄį ž°įŪöĆŽ•ľ žúĄŪēī JOINžĚÄ žú†žßÄ */ LEFT JOIN company sender ON w.sender_company_id = sender.company_id LEFT JOIN company receiver ON w.receiver_company_id = receiver.company_id WHERE w.del_yn = 'N'
AND w.waybill_id = #{waybillId}
/* Í≤ÄžÉČ žčú ŽĎź žĽ¨Žüľ Ž™®ŽĎź ŪôēžĚł */ AND ( w.sender_company_nm LIKE CONCAT('%', #{senderCompanyNm}, '%') OR sender.company_nm LIKE CONCAT('%', #{senderCompanyNm}, '%') )
/* Í≤ÄžÉČ žčú ŽĎź žĽ¨Žüľ Ž™®ŽĎź ŪôēžĚł */ AND ( w.receiver_company_nm LIKE CONCAT('%', #{receiverCompanyNm}, '%') OR receiver.company_nm LIKE CONCAT('%', #{receiverCompanyNm}, '%') )
AND ( w.start_no LIKE CONCAT('%', REPLACE(#{searchNo}, '-', ''), '%') OR w.end_no LIKE CONCAT('%', REPLACE(#{searchNo}, '-', ''), '%') )
ORDER BY w.waybill_id DESC

WITH base AS ( SELECT w.waybill_id, w.qty, COALESCE(w.start_no, '') AS start_no, COALESCE(w.end_no, '') AS end_no, w.sender_company_id, /* COALESCEŽ°ú žöįžĄ†žąúžúĄ žßÄž†ē */ COALESCE(w.sender_company_nm, sender.company_nm) AS sender_company_nm, w.sender_tel_no AS sender_tel_no, w.sender_manager_tel_no AS sender_manager_tel_no, COALESCE(w.sender_address, '') AS sender_address, w.receiver_company_id, /* COALESCEŽ°ú žöįžĄ†žąúžúĄ žßÄž†ē */ COALESCE(w.receiver_company_nm, receiver.company_nm) AS receiver_company_nm, w.receiver_tel_no AS receiver_tel_no, w.receiver_manager_tel_no AS receiver_manager_tel_no, COALESCE(w.receiver_address, '') AS receiver_address, w.reg_id, w.reg_dt, w.chg_id, w.chg_dt, w.del_yn, w.charge_cd FROM waybill w /* JOIN žú†žßÄ */ LEFT JOIN company sender ON w.sender_company_id = sender.company_id LEFT JOIN company receiver ON w.receiver_company_id = receiver.company_id WHERE w.del_yn = 'N'
AND w.waybill_id = #{waybillId}
AND ( w.sender_company_nm ILIKE CONCAT('%', #{senderCompanyNm}, '%') OR sender.company_nm ILIKE CONCAT('%', #{senderCompanyNm}, '%') OR ( LENGTH(regexp_replace(#{senderCompanyNm}, '[^0-9]', '', 'g')) = 4 AND ( RIGHT(regexp_replace(COALESCE(w.sender_tel_no, ''), '[^0-9]', '', 'g'), 4) = regexp_replace(#{senderCompanyNm}, '[^0-9]', '', 'g') OR RIGHT(regexp_replace(COALESCE(w.sender_manager_tel_no, ''), '[^0-9]', '', 'g'), 4) = regexp_replace(#{senderCompanyNm}, '[^0-9]', '', 'g') ) ) )
AND ( w.receiver_company_nm ILIKE CONCAT('%', #{receiverCompanyNm}, '%') OR receiver.company_nm ILIKE CONCAT('%', #{receiverCompanyNm}, '%') OR ( LENGTH(regexp_replace(#{receiverCompanyNm}, '[^0-9]', '', 'g')) = 4 AND ( RIGHT(regexp_replace(COALESCE(w.receiver_tel_no, ''), '[^0-9]', '', 'g'), 4) = regexp_replace(#{receiverCompanyNm}, '[^0-9]', '', 'g') OR RIGHT(regexp_replace(COALESCE(w.receiver_manager_tel_no, ''), '[^0-9]', '', 'g'), 4) = regexp_replace(#{receiverCompanyNm}, '[^0-9]', '', 'g') ) ) )
AND ( REPLACE(COALESCE(w.start_no, ''), '-', '') ILIKE ('%' || REPLACE(#{searchNo}, '-', '') || '%') OR REPLACE(COALESCE(w.end_no, ''), '-', '') ILIKE ('%' || REPLACE(#{searchNo}, '-', '') || '%') )
) SELECT waybill_id AS waybillId, qty, start_no AS startNo, end_no AS endNo, sender_company_id AS senderCompanyId, sender_company_nm AS senderCompanyNm, sender_tel_no AS senderTelNo, sender_manager_tel_no AS senderManagerTelNo, sender_address AS senderAddress, receiver_company_id AS receiverCompanyId, receiver_company_nm AS receiverCompanyNm, receiver_tel_no AS receiverTelNo, receiver_manager_tel_no AS receiverManagerTelNo, receiver_address AS receiverAddress, reg_id AS regId, reg_dt AS regDt, chg_id AS chgId, chg_dt AS chgDt, del_yn AS delYn, charge_cd AS chargeCd, COUNT(*) OVER() AS total FROM base b
ORDER BY ${orderBy}
ORDER BY b.waybill_id DESC
LIMIT #{limit} OFFSET #{offset}
